If you want to use it along with Qt see the QMacCocoaViewContainer. Then the following code should work: {
NSView*video=[[NSViewalloc]init];
QMacCocoaViewContainer*container=newQMacCocoaViewContainer(video,parent);
libvlc_media_player_set_nsobject(mp,video);
[videorelease];
}
